def update_bullets(bullets: list, targets: list, step: float) -> None:
    global score
    bi = 0
    while bi < len(bullets):
        b = bullets[bi]
        if b.life > 0.0:
            b.x += b.vx * step
            b.y += b.vy * step
            b.z += b.vz * step
            b.life -= step
